import React, { useState, useEffect } from "react";
import { useParams, Link } from "react-router-dom";
import axios from "axios";
import "./Recipes.css";

const Recipes = () => {
  const { category } = useParams();
  const [recipes, setRecipes] = useState([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    category: category || "",
    cuisine: "",
    difficulty: "",
    search: "",
  });

  useEffect(() => {
    fetchRecipes();
  }, [filters, category]);

  const fetchRecipes = async () => {
    setLoading(true);
    try {
      const params = new URLSearchParams();
      Object.keys(filters).forEach((key) => {
        if (filters[key]) params.append(key, filters[key]);
      });

      const response = await axios.get(
        `http://localhost:5000/api/recipes?${params}`
      );
      setRecipes(response.data.recipes);
    } catch (error) {
      console.error("Error fetching recipes:", error);
    } finally {
      setLoading(false);
    }
  };

  const handleFilterChange = (key, value) => {
    setFilters((prev) => ({ ...prev, [key]: value }));
  };

  if (loading) {
    return <div className="loading">Loading recipes...</div>;
  }

  return (
    <div className="recipes-page">
      <div className="recipes-header">
        <h1>
          {category
            ? `${category.charAt(0).toUpperCase() + category.slice(1)} Recipes`
            : "All Recipes"}
        </h1>
        <Link to="/add-recipe" className="add-recipe-btn">
          Add New Recipe
        </Link>
      </div>

      <div className="filters">
        <input
          type="text"
          placeholder="Search recipes..."
          value={filters.search}
          onChange={(e) => handleFilterChange("search", e.target.value)}
          className="search-input"
        />
        <select
          value={filters.category}
          onChange={(e) => handleFilterChange("category", e.target.value)}
        >
          <option value="">All Categories</option>
          <option value="indian">Indian</option>
          <option value="chinese">Chinese</option>
          <option value="italian">Italian</option>
          <option value="mexican">Mexican</option>
          <option value="thai">Thai</option>
          <option value="american">American</option>
        </select>
        <select
          value={filters.difficulty}
          onChange={(e) => handleFilterChange("difficulty", e.target.value)}
        >
          <option value="">Any Difficulty</option>
          <option value="easy">Easy</option>
          <option value="medium">Medium</option>
          <option value="hard">Hard</option>
        </select>
      </div>

      <div className="recipes-grid">
        {recipes.map((recipe) => (
          <div key={recipe._id} className="recipe-card">
            <img
              src={
                recipe.image
                  ? `http://localhost:5000/uploads/${recipe.image}`
                  : "/placeholder-recipe.jpg"
              }
              alt={recipe.title}
            />
            <div className="recipe-info">
              <h3>{recipe.title}</h3>
              <p className="category">{recipe.category}</p>
              <p className="cuisine">{recipe.cuisine}</p>
              <p className="description">
                {recipe.description.substring(0, 100)}...
              </p>
              <div className="recipe-meta">
                <span>⏱️ {recipe.prepTime + recipe.cookTime} mins</span>
                <span>👥 {recipe.servings} servings</span>
                <span className={`difficulty ${recipe.difficulty}`}>
                  {recipe.difficulty}
                </span>
              </div>
              <div className="recipe-actions">
                <Link to={`/recipes/${recipe._id}`} className="view-recipe-btn">
                  View Recipe
                </Link>
              </div>
            </div>
          </div>
        ))}
      </div>

      {recipes.length === 0 && (
        <div className="no-recipes">
          <p>
            No recipes found. Try adjusting your filters or add a new recipe!
          </p>
        </div>
      )}
    </div>
  );
};

export default Recipes;
